package com.example.ytpodcast.pluginsimport com.example.ytpodcast.models.ErrorResponseimport com.example.ytpodcast.models.PodcastFeedRequestimport com.example.ytpodcast.service.AudioConverterServiceimport com.example.ytpodcast.service.RssFeedServiceimport com.example.ytpodcast.service.YouTubeServiceimport io.ktor.http.*import io.ktor.server.application.*import io.ktor.server.request.*import io.ktor.server.response.*import io.ktor.server.routing.*import org.slf4j.LoggerFactoryfun Application.configureRouting(    youTubeService: YouTubeService,    audioConverterService: AudioConverterService,    rssFeedService: RssFeedService) {    val logger = LoggerFactory.getLogger("Routing")        routing {        get("/") {            call.respondText("YouTube to Podcast RSS Feed Converter")        }                // Health check endpoint        get("/health") {            call.respond(HttpStatusCode.OK, mapOf("status" to "healthy"))        }                // Convert playlist to RSS feed        post("/api/playlist/feed") {            try {                val request = call.receive<PodcastFeedRequest>()                logger.info("Received request to convert playlist: ${request.playlistUrl}")                                val playlistInfo = youTubeService.getPlaylistInfo(request.playlistUrl)                                // Generate base URL from request                val baseUrl = "${call.request.origin.scheme}://${call.request.host()}:${call.request.port()}"                                val rssFeed = rssFeedService.generatePodcastFeed(playlistInfo, baseUrl)                                call.respondText(rssFeed, ContentType.Application.Rss)            } catch (e: IllegalArgumentException) {                logger.warn("Invalid playlist URL", e)                call.respond(                    HttpStatusCode.BadRequest,                    ErrorResponse("invalid_request", e.message ?: "Invalid playlist URL")                )            } catch (e: Exception) {                logger.error("Failed to generate RSS feed", e)                call.respond(                    HttpStatusCode.InternalServerError,                    ErrorResponse("internal_error", "Failed to generate RSS feed")                )            }        }                // Get RSS feed for a playlist        get("/feed/{playlistId}") {            try {                val playlistId = call.parameters["playlistId"]                     ?: return@get call.respond(                        HttpStatusCode.BadRequest,                        ErrorResponse("invalid_request", "Missing playlist ID")                    )                                logger.info("Fetching RSS feed for playlist: $playlistId")                                val playlistInfo = youTubeService.getPlaylistInfo(playlistId)                                // Generate base URL from request                val baseUrl = "${call.request.origin.scheme}://${call.request.host()}:${call.request.port()}"                                val rssFeed = rssFeedService.generatePodcastFeed(playlistInfo, baseUrl)                                call.respondText(rssFeed, ContentType.Application.Rss)            } catch (e: Exception) {                logger.error("Failed to get RSS feed", e)                call.respond(                    HttpStatusCode.InternalServerError,                    ErrorResponse("internal_error", "Failed to get RSS feed")                )            }        }                // Get episode audio file        get("/show/{showId}/episodes/{episodeId}.mp3") {            try {                val showId = call.parameters["showId"]                val episodeIdWithExt = call.parameters["episodeId"]                                if (showId == null || episodeIdWithExt == null) {                    return@get call.respond(                        HttpStatusCode.BadRequest,                        ErrorResponse("invalid_request", "Missing show or episode ID")                    )                }                                // Remove .mp3 extension if present                val episodeId = episodeIdWithExt.removeSuffix(".mp3")                                logger.info("Fetching audio for episode $episodeId from show $showId")                                // Get audio from YouTube                val audioData = youTubeService.getAudioStream(episodeId)                                // Check if conversion is needed                val mp3Data = if (audioConverterService.isValidAudioFormat(audioData)) {                    // Convert to MP3                    logger.info("Converting audio to MP3 for episode $episodeId")                    val converted = audioConverterService.convertToMp3(audioData, episodeId)                    converted.data                } else {                    logger.warn("Invalid audio format for episode $episodeId, attempting conversion anyway")                    val converted = audioConverterService.convertToMp3(audioData, episodeId)                    converted.data                }                                // Set appropriate headers for audio streaming                call.response.header(HttpHeaders.ContentType, "audio/mpeg")                call.response.header(HttpHeaders.ContentDisposition, "inline; filename=\"$episodeId.mp3\"")                call.response.header(HttpHeaders.AcceptRanges, "bytes")                call.response.header(HttpHeaders.ContentLength, mp3Data.size.toString())                                // Support for range requests (for seeking in podcast players)                val range = call.request.header(HttpHeaders.Range)                if (range != null && range.startsWith("bytes=")) {                    val rangeSpec = range.substring(6)                    val rangeParts = rangeSpec.split("-")                    val start = rangeParts[0].toLongOrNull() ?: 0                    val end = if (rangeParts.size > 1 && rangeParts[1].isNotEmpty()) {                        rangeParts[1].toLongOrNull() ?: (mp3Data.size - 1).toLong()                    } else {                        (mp3Data.size - 1).toLong()                    }                                        val actualEnd = minOf(end, (mp3Data.size - 1).toLong())                    val contentLength = actualEnd - start + 1                                        call.response.status(HttpStatusCode.PartialContent)                    call.response.header(                        HttpHeaders.ContentRange,                        "bytes $start-$actualEnd/${mp3Data.size}"                    )                    call.response.header(HttpHeaders.ContentLength, contentLength.toString())                                        call.respondBytes(mp3Data.sliceArray(start.toInt()..actualEnd.toInt()))                } else {                    call.respondBytes(mp3Data)                }            } catch (e: Exception) {                logger.error("Failed to get episode audio", e)                call.respond(                    HttpStatusCode.InternalServerError,                    ErrorResponse("internal_error", "Failed to get episode audio")                )            }        }                // Get playlist info        get("/api/playlist/{playlistId}") {            try {                val playlistId = call.parameters["playlistId"]                    ?: return@get call.respond(                        HttpStatusCode.BadRequest,                        ErrorResponse("invalid_request", "Missing playlist ID")                    )                                logger.info("Getting info for playlist: $playlistId")                                val playlistInfo = youTubeService.getPlaylistInfo(playlistId)                call.respond(playlistInfo)            } catch (e: Exception) {                logger.error("Failed to get playlist info", e)                call.respond(                    HttpStatusCode.InternalServerError,                    ErrorResponse("internal_error", "Failed to get playlist info")                )            }        }                // Get video info        get("/api/video/{videoId}") {            try {                val videoId = call.parameters["videoId"]                    ?: return@get call.respond(                        HttpStatusCode.BadRequest,                        ErrorResponse("invalid_request", "Missing video ID")                    )                                logger.info("Getting info for video: $videoId")                                val videoInfo = youTubeService.getVideoInfo(videoId)                call.respond(videoInfo)            } catch (e: Exception) {                logger.error("Failed to get video info", e)                call.respond(                    HttpStatusCode.InternalServerError,                    ErrorResponse("internal_error", "Failed to get video info")                )            }        }    }}